"""Определения tool'ов для OpenAI tool-calling API и их диспетчер.

Каждый tool — pure function над аргументами JSON + ctx; возвращает JSON-сериализуемый
dict (он попадает в `tool` сообщение). Любая ошибка возвращается полем `error`,
а не raise — модель должна иметь шанс восстановиться.
"""

from __future__ import annotations

import json
import re
from dataclasses import dataclass, field
from typing import Any, Callable

import oracledb

from .config import Config
from .db import SQLValidationError, execute_query
from .schema import describe_table
from .sql_lint import detect_double_counting

# Year-consistency check (Run 4 failure mode):
# `_YEAR_RE` — все 4-значные годы 20xx в произвольном тексте (использовалось
# в ответе, вопросе, SQL).
# `_DATE_YEAR_RE` — только год, лежащий внутри ISO-даты (`YYYY-MM-DD`,
# `YYYY-MM`, `YYYY/MM/DD`). Используется ТОЛЬКО для извлечения года из
# значений ячеек результата SQL: голое число 2025 в результате COUNT
# не должно засчитываться как «год есть в данных» (CRITIC pass-2 F3).
_YEAR_RE = re.compile(r"\b(20\d{2})\b")
_DATE_YEAR_RE = re.compile(r"\b(20\d{2})[-/]\d{1,2}(?:[-/]\d{1,2})?\b")
# Имя колонки должно «выглядеть как дата», чтобы её значения учитывались
# в data_years. Закрывает CRITIC pass-4 Finding 1: иначе модель могла
# поднять год через `SELECT SYSDATE` или произвольный string-литерал, в
# котором случайно встретилась дата-форма.
_DATE_COL_NAME_RE = re.compile(r"(?:_DT$|_DATE$|^DT$|^MONTH_DT$)", re.IGNORECASE)

# Публичный реестр имён tool'ов — единый источник правды.
TOOL_INSPECT_SCHEMA = "inspect_schema"
TOOL_EXECUTE_SQL = "execute_sql"
TOOL_VALIDATE_RESULT = "validate_result"
TOOL_FINAL_ANSWER = "final_answer"


TOOLS_SCHEMA: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": TOOL_INSPECT_SCHEMA,
            "description": (
                "Вернуть структурированное описание таблицы и её полей "
                "(бизнес-семантика, типы, единицы, примеры SQL). "
                "Полезно перед первой генерацией SQL — даёт точные имена "
                "колонок и предупреждения о суммирующих/итоговых полях."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы. По умолчанию client_product.",
                        "default": "client_product",
                    }
                },
                "required": [],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": TOOL_EXECUTE_SQL,
            "description": (
                "Выполнить SELECT/WITH-запрос к Oracle и получить таблицу "
                "результатов. Разрешены только read-only запросы. Результат "
                "обрезается до 200 строк."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "sql": {
                        "type": "string",
                        "description": (
                            "Корректный Oracle SQL (SELECT или WITH). "
                            "Без точки с запятой в конце."
                        ),
                    }
                },
                "required": ["sql"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": TOOL_VALIDATE_RESULT,
            "description": (
                "Sanity-check последнего результата execute_sql: соответствует "
                "ли он ожиданиям (число строк, ненулевые ключевые поля, "
                "разумные диапазоны). Возвращает список замечаний."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "expectations": {
                        "type": "object",
                        "description": (
                            "Что проверить. Ключи: "
                            "min_rows (int), max_rows (int), "
                            "non_null_columns (list[str]), "
                            "numeric_ranges (object: column -> {min,max}), "
                            "expect_non_empty (bool)."
                        ),
                    }
                },
                "required": ["expectations"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": TOOL_FINAL_ANSWER,
            "description": (
                "Сформулировать ИТОГОВЫЙ ответ пользователю и завершить "
                "работу. Текст ответа должен содержать конкретные цифры "
                "из БД, единицы измерения и краткую интерпретацию. "
                "После вызова этого tool'а работа агента завершается."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "answer": {
                        "type": "string",
                        "description": "Финальный естественно-языковой ответ.",
                    },
                    "supporting_numbers": {
                        "type": "array",
                        "description": "Опционально: ключевые числа/метки.",
                        "items": {"type": "string"},
                    },
                },
                "required": ["answer"],
            },
        },
    },
]


@dataclass
class ToolContext:
    """Состояние агента между вызовами tool'ов."""

    config: Config
    user_question: str = ""
    last_result: dict[str, Any] | None = None
    final_answer: str | None = None
    final_supporting: list[str] = field(default_factory=list)
    sql_history: list[str] = field(default_factory=list)
    nudged_on_empty: bool = False
    final_answer_attempts: int = 0


# ---- реализации tool'ов ----------------------------------------------------


def _inspect_schema(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    table = args.get("table") or "client_product"
    try:
        return describe_table(table)
    except ValueError as exc:
        return {"error": str(exc)}


def _execute_sql(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    sql = args.get("sql", "")
    ctx.sql_history.append(sql)
    try:
        result = execute_query(sql, ctx.config)
    except SQLValidationError as exc:
        return {"error": f"SQL отклонён: {exc}"}
    except oracledb.Error as exc:
        return {"error": f"Oracle ошибка: {exc}"}
    payload: dict[str, Any] = {
        "columns": result.columns,
        "rows": result.rows,
        "row_count": result.row_count,
        "truncated": result.truncated,
    }
    # Статический lint итоговое+составляющие — сигнал модели, не блок.
    lint_warnings = detect_double_counting(sql)
    if lint_warnings:
        payload["warnings"] = lint_warnings
    ctx.last_result = payload
    return payload


def _validate_result(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    if ctx.last_result is None:
        return {"ok": False, "issues": ["Нет результата для валидации — сначала execute_sql."]}
    expectations_raw = args.get("expectations", {})
    if not isinstance(expectations_raw, dict):
        return {
            "ok": False,
            "issues": [
                "expectations должен быть JSON-объектом, "
                f"получено: {type(expectations_raw).__name__}"
            ],
        }
    expectations = expectations_raw
    cols: list[str] = ctx.last_result["columns"]
    rows: list[list[Any]] = ctx.last_result["rows"]
    issues: list[str] = []

    if expectations.get("expect_non_empty") and not rows:
        issues.append("Ожидался непустой результат, но строк нет.")

    for key in ("min_rows", "max_rows"):
        bound = expectations.get(key)
        if bound is None:
            continue
        try:
            bound_int = int(bound)
        except (TypeError, ValueError):
            issues.append(f"{key} должен быть int, получено {bound!r}.")
            continue
        if key == "min_rows" and len(rows) < bound_int:
            issues.append(f"Строк {len(rows)} < min_rows={bound_int}.")
        if key == "max_rows" and len(rows) > bound_int:
            issues.append(f"Строк {len(rows)} > max_rows={bound_int}.")

    non_null_cols = expectations.get("non_null_columns") or []
    if isinstance(non_null_cols, (str, bytes)) or not hasattr(non_null_cols, "__iter__"):
        issues.append("non_null_columns должен быть списком имён колонок.")
        non_null_cols = []
    for col in non_null_cols:
        col = str(col)
        if col not in cols:
            issues.append(f"Колонка {col!r} отсутствует в результате.")
            continue
        idx = cols.index(col)
        if any(row[idx] is None for row in rows):
            issues.append(f"В колонке {col!r} есть NULL.")

    numeric_ranges = expectations.get("numeric_ranges") or {}
    if not isinstance(numeric_ranges, dict):
        issues.append("numeric_ranges должен быть JSON-объектом {колонка: {min,max}}.")
        numeric_ranges = {}
    for col, rng in numeric_ranges.items():
        col = str(col)
        if not isinstance(rng, dict):
            issues.append(f"numeric_ranges[{col!r}] должен быть объектом {{min,max}}.")
            continue
        if col not in cols:
            issues.append(f"Колонка {col!r} (range-check) отсутствует.")
            continue
        idx = cols.index(col)
        mn_r = rng.get("min")
        mx_r = rng.get("max")
        for row in rows:
            value = row[idx]
            if value is None:
                continue
            try:
                v = float(value)
            except (TypeError, ValueError):
                issues.append(f"Колонка {col!r}: значение {value!r} не число.")
                continue
            if mn_r is not None:
                try:
                    if v < float(mn_r):
                        issues.append(f"{col}={v} < min {mn_r}")
                except (TypeError, ValueError):
                    issues.append(f"min для {col!r} не число: {mn_r!r}")
            if mx_r is not None:
                try:
                    if v > float(mx_r):
                        issues.append(f"{col}={v} > max {mx_r}")
                except (TypeError, ValueError):
                    issues.append(f"max для {col!r} не число: {mx_r!r}")

    return {
        "ok": not issues,
        "issues": issues,
        "row_count": len(rows),
        "columns": cols,
    }


def _collect_years_in_result(ctx: ToolContext) -> set[str]:
    """Годы, фактически встречающиеся в `last_result` КАК ЧАСТЬ ДАТЫ.

    Важно: `COUNT(*) = 2025` не должен быть признан «год 2025 в данных»;
    учитываем только значения, в которых год идёт в ISO-форме `YYYY-MM[-DD]`
    или `YYYY/MM[/DD]`. После `db._normalize` все даты приведены к ISO.
    Закрывает CRITIC pass-2 F3 (числа-омонимы годов).
    """
    years: set[str] = set()
    if not ctx.last_result:
        return years
    for row in ctx.last_result.get("rows", []):
        for value in row:
            if value is None:
                continue
            years.update(_DATE_YEAR_RE.findall(str(value)))
    return years


def check_year_consistency(answer: str, ctx: ToolContext) -> str | None:
    """Возвращает сообщение о rogue годах в `answer`, либо None.

    Public function — используется и из `_final_answer`, и из content-fallback
    пути в `agent.run` (когда модель возвращает текст без tool-вызова).

    Allowed-источники: ТОЛЬКО (а) годы из user_question и (б) ISO-датоподобные
    значения из last_result. `sql_history` сознательно НЕ включён (CRITIC
    pass-3 Finding 2): иначе модель может self-whitelist'ить rogue год,
    написав `WHERE MONTH_DT >= DATE '2026-01-01'` против данных, которые
    кончаются 2025-06. Если модели нужен год для упоминания — добавить
    MONTH_DT в SELECT и взять его из результата.
    """
    answer_years = set(_YEAR_RE.findall(answer))
    if not answer_years:
        return None
    question_years = set(_YEAR_RE.findall(ctx.user_question))
    data_years = _collect_years_in_result(ctx)
    allowed = question_years | data_years
    rogue = answer_years - allowed
    if not rogue:
        return None
    return (
        f"В тексте ответа упомянуты годы {sorted(rogue)}, которых нет ни в "
        f"вопросе ({sorted(question_years) or '—'}), ни в данных результата "
        f"({sorted(data_years) or '—'}). Перепиши ответ, используя только "
        f"годы из этих источников. Если в результате нет MONTH_DT — добавь "
        f"его в SELECT и перевыполни SQL перед final_answer."
    )


def _final_answer(args: dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    text = (args.get("answer") or "").strip()
    if not text:
        return {"error": "Пустой ответ — final_answer требует поле answer."}

    # Year-consistency sanity-check (Run 4 failure mode из EVIDENCE.md):
    # модель может корректно посчитать цифры, но в текстовой обёртке
    # сослаться на год, которого нет ни в SQL, ни в данных, ни в вопросе.
    # Reject всегда — max_steps в agent.run защищает от loop'а. Прежняя
    # «retry once → accept» семантика эксплуатировалась (CRITIC pass-2 F4/F5):
    # модель сабмитила тот же rogue ответ дважды и проходила. Лучше упасть
    # с max_steps, чем выдать заведомо неверную метку даты.
    ctx.final_answer_attempts += 1
    warning = check_year_consistency(text, ctx)
    if warning:
        return {"error": warning}

    ctx.final_answer = text
    supporting = args.get("supporting_numbers") or []
    if isinstance(supporting, list):
        ctx.final_supporting = [str(x) for x in supporting]
    return {"ok": True}


_DISPATCH: dict[str, Callable[[dict[str, Any], ToolContext], dict[str, Any]]] = {
    TOOL_INSPECT_SCHEMA: _inspect_schema,
    TOOL_EXECUTE_SQL: _execute_sql,
    TOOL_VALIDATE_RESULT: _validate_result,
    TOOL_FINAL_ANSWER: _final_answer,
}


def dispatch(name: str, raw_args: str | dict[str, Any], ctx: ToolContext) -> dict[str, Any]:
    """Парсит аргументы и вызывает tool по имени.

    OpenAI SDK отдаёт `function.arguments` строкой; некоторые Ollama-сборки
    отдают сразу dict — поддерживаем оба случая.

    Любая ошибка handler'а (включая нештатные AttributeError на кривом
    payload'е) превращается в `{"error": ...}`, чтобы модель могла
    восстановиться, а не убивать сессию.
    """
    handler = _DISPATCH.get(name)
    if handler is None:
        return {"error": f"Неизвестный tool: {name}"}

    if isinstance(raw_args, dict):
        args = raw_args
    elif raw_args in (None, "", b""):
        args = {}
    else:
        try:
            args = json.loads(raw_args)
        except json.JSONDecodeError as exc:
            return {"error": f"Невалидный JSON аргументов: {exc}"}
    if not isinstance(args, dict):
        return {"error": "Аргументы должны быть JSON-объектом."}

    try:
        return handler(args, ctx)
    except Exception as exc:  # noqa: BLE001 — модель должна получить шанс на ретрай
        return {"error": f"Сбой tool'а {name!r}: {type(exc).__name__}: {exc}"}

